export interface InspectionStep {
  step: number;
  description: string;
  criteria: string;
  technique: string;
}

export interface InspectionSheet {
  responsibility: string;
  estimatedTime: string;
  safetyPrecautions: string;
  toolsRequired: string;
  steps: InspectionStep[];

  checkPointDescription?: string;
  type?: 'Qualitative' | 'Quantitative';
  criteriaLimits?: string; 
  normalCondition?: string; 
}

export interface ComponentIntel {
  description: string;
  location: string;
  visualCues: string;
}

export type ConsequenceCategory = 
  | 'Hidden - Safety/Env' 
  | 'Hidden - Operational' 
  | 'Evident - Safety/Env' 
  | 'Evident - Operational'
  | 'Evident - Non-Operational';

export interface RCMItem {
  id: string;
  component: string;
  functionType: 'Primary' | 'Secondary';
  function: string;
  functionalFailure: string;
  failureMode: string;
  failureEffect: string;
  criticality: 'High' | 'Medium' | 'Low';

  consequenceCategory: ConsequenceCategory;
  iso14224Code: string;

  severity: number;
  occurrence: number;
  detection: number;
  rpn: number;

  maintenanceTask: string;
  interval: string;
  pfInterval?: string; // New field for reliability optimization
  taskType: 'Condition Monitoring' | 'Time-Based' | 'Run-to-Failure' | 'Redesign' | 'Failure Finding' | 'Lubrication' | 'Servicing' | 'Restoration' | 'Replacement' | 'Training' | 'Procedural Change';
  inspectionSheet?: InspectionSheet;
  componentIntel?: ComponentIntel;
  isNew?: boolean;
  isMiraGenerated?: boolean;
  validationIssues?: string[];
}

export interface AnalysisStats {
  totalItems: number;
  highRisk: number;
  mediumRisk: number;
  lowRisk: number;
}

export type InputMode = 'manual' | 'upload';

export interface FileData {
  name: string;
  mimeType: string;
  data: string;
}

export interface Folder {
  id: string;
  name: string;
  timestamp: number;
}

export interface SavedStudy {
  id: string;
  name: string;
  timestamp: number;
  items: RCMItem[];
  contextText: string;
  language?: string;
  fileName?: string;
  folderId?: string;
  isFinished?: boolean;
}

import { GoogleGenAI } from "@google/genai";
import React, { useState, useRef, useEffect } from 'react';
import { RCMItem, ConsequenceCategory } from '../types';
import { 
  X, Send, Sparkles, ChevronDown, 
  Plus, CheckCircle2, Search, 
  UserCheck, ShieldAlert, Zap, Loader2, LayoutGrid, 
  ChevronRight, RotateCcw, Target, Info, AlertTriangle, Wrench, Box, Activity, FileText, ClipboardList, Database, ShieldX, ClipboardCheck
} from 'lucide-react';

interface AICopilotProps {
  data: RCMItem[] | null;
  onUpdate: (newData: RCMItem[]) => void;
  language: string;
}

interface ProposedAction {
  id: string; 
  type: 'ADD' | 'UPDATE' | 'DELETE';
  item: Partial<RCMItem>;
  reason: string;
  applied?: boolean;
}

interface Message {
  role: 'user' | 'model';
  text: string;
  proposals?: ProposedAction[];
  isFacilitatorInsight?: boolean;
}

const FormattedMessage: React.FC<{ text: string; role: 'user' | 'model'; isFacilitator?: boolean }> = ({ text, role }) => {
  const lines = (text || '').split('\n');

  return (
    <div className={`space-y-2 ${role === 'model' ? 'text-slate-700' : 'text-white'}`}>
      {lines.map((line, idx) => {
        const trimmed = line.trim();
        const cleanLine = line.replace(/\*\*/g, '').replace(/#/g, '').trim();
        if (!cleanLine) return <div key={idx} className="h-2" />;

        const isQuestion = cleanLine.endsWith('?');

        if (trimmed.startsWith('* ') || trimmed.startsWith('- ')) {
          return (
            <div key={idx} className="flex gap-2 pl-2">
              <ChevronRight size={12} className={`shrink-0 mt-1 ${role === 'model' ? 'text-indigo-400' : 'text-white opacity-50'}`} />
              <span className={`flex-1 text-[13px] font-medium leading-relaxed ${isQuestion ? 'text-indigo-700 font-bold italic' : ''}`}>
                {cleanLine.replace(/^[*|-]\s*/, '')}
              </span>
            </div>
          );
        }

        return (
          <p key={idx} className={`leading-relaxed text-[13px] font-medium ${isQuestion && role === 'model' ? 'bg-indigo-50 p-2 rounded-lg border-l-4 border-indigo-600 text-indigo-900 shadow-sm' : ''}`}>
            {cleanLine}
          </p>
        );
      })}
    </div>
  );
};

export const AICopilot: React.FC<AICopilotProps> = ({ data, onUpdate, language }) => {
  const [isOpen, setIsOpen] = useState(false);
  const [input, setInput] = useState('');
  const [messages, setMessages] = useState<Message[]>([]);
  const [isLoading, setIsLoading] = useState(false);

  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (isOpen && scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [isOpen, messages, isLoading]);

  const parseAIResponse = (text: string): { cleanText: string, proposals?: ProposedAction[] } => {
    const actionRegex = /<ACTION>([\s\S]*?)<\/ACTION>/gi;
    const proposals: ProposedAction[] = [];
    let cleanText = text;
    let match;

    while ((match = actionRegex.exec(text)) !== null) {
      try {
        let content = match[1].trim();
        content = content.replace(/^```json\s*/i, '').replace(/\s*```$/i, '').trim();

        if (content.startsWith('(') && content.endsWith(')')) {
          content = content.substring(1, content.length - 1);
        }

        const raw = JSON.parse(content);
        const actions = Array.isArray(raw) ? raw : [raw];

        actions.forEach((a: any) => {
          if (a && typeof a === 'object') {
            const itemData = a.item || a.data || (a.component ? a : null);
            if (itemData && itemData.component) {
              proposals.push({
                id: `proposal-${Math.random().toString(36).substr(2, 9)}`,
                type: a.type || 'ADD',
                reason: a.reason || 'Strategic RCM recommendation synthesized by MIRA.',
                item: itemData,
                applied: false
              });
            }
          }
        });
      } catch (e) {
        console.error("MIRA Extraction Error: Tag found but JSON invalid.", e);
      }
    }

    const textWithoutActions = text.replace(/<ACTION>[\s\S]*?<\/ACTION>/gi, '').trim();
    return { cleanText: textWithoutActions, proposals: proposals.length > 0 ? proposals : undefined };
  };

  const RCM_FIELDS_PROMPT = `
    The JSON object MUST include ALL these fields for table compatibility:
    - component (string)
    - functionType (string: 'Primary' or 'Secondary')
    - function (string)
    - functionalFailure (string)
    - failureMode (string)
    - failureEffect (string)
    - consequenceCategory (string: 'Hidden - Safety/Env', 'Hidden - Operational', 'Evident - Safety/Env', 'Evident - Operational', 'Evident - Non-Operational')
    - iso14224Code (string: 3-letter code)
    - severity (number: 1-10)
    - occurrence (number: 1-10)
    - detection (number: 1-10)
    - maintenanceTask (string)
    - interval (string)
    - taskType (string: 'Condition Monitoring', 'Time-Based', 'Run-to-Failure', 'Redesign', 'Failure Finding', 'Lubrication', 'Servicing', 'Restoration', 'Replacement', 'Training', 'Procedural Change')
    - componentIntel (object: { description, location, visualCues })
  `;

  const handleFacilitatorAudit = async () => {
    if (!data || data.length === 0) return;
    setIsLoading(true);

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
      const studySummary = data.slice(-30).map(i => ({
        comp: i.component,
        fail: i.failureMode,
        task: i.maintenanceTask,
        rpn: i.rpn
      }));

      const prompt = `
        MIRA Facilitator, perform a STRATEGIC AUDIT of this RCM study: ${JSON.stringify(studySummary)}
        Language: ${language}

        TASK:
        1. Evaluate the holistic quality of the reliability strategy.
        2. Identify 3-5 critical technical gaps (missing components or failure modes).
        3. Propose each gap as a complete RCM record inside <ACTION> tags.

        ${RCM_FIELDS_PROMPT}

        Descriptions and tasks MUST be in ${language}.
      `;

      const response = await ai.models.generateContent({
        model: 'gemini-3-pro-preview',
        contents: [{ role: 'user', parts: [{ text: prompt }] }],
        config: {
          thinkingConfig: { thinkingBudget: 32768 },
          temperature: 0.3,
          seed: 42,
          systemInstruction: `You are MIRA, the Lead RCM Facilitator. You are professional, encouraging, and technically rigorous. You synthesize world-class reliability strategies in ${language} and always provide implementable <ACTION> records.`
        }
      });

      const { cleanText, proposals } = parseAIResponse(response.text || "");
      setMessages(prev => [...prev, { 
        role: 'model', 
        text: cleanText || "Strategic audit complete. Actionable additions generated.", 
        proposals, 
        isFacilitatorInsight: true 
      }]);
    } catch (e) {
      console.error(e);
      setMessages(prev => [...prev, { role: 'model', text: "Audit system temporarily offline." }]);
    } finally {
      setIsLoading(false);
    }
  };

  const handleSend = async () => {
    if (!input.trim() || isLoading) return;

    const userMsg = input.trim();
    setInput('');
    setMessages(prev => [...prev, { role: 'user', text: userMsg }]);
    setIsLoading(true);

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
      const prompt = `
        USER REQUEST: "${userMsg}"
        CURRENT STUDY CONTEXT: ${JSON.stringify((data || []).slice(-15).map(i => ({ c: i.component, fm: i.failureMode })))}
        LANGUAGE: ${language}

        MIRA FACILITATOR INTERACTION:
        1. Respond as a professional RCM mentor. Be interactive and technically insightful.
        2. If the user asks for new components, failure modes, or tasks, you MUST synthesize a FULL RCM record.
        3. Even if they don't explicitly ask for an "addition", if their request implies a strategy change, provide the record.
        4. ALL ACTIONABLE RECORDS MUST BE WRAPPED IN <ACTION> tags with the following schema:

        ${RCM_FIELDS_PROMPT}

        5. Ensure all technical descriptions in the JSON are in ${language}.
      `;

      const response = await ai.models.generateContent({
        model: 'gemini-3-pro-preview',
        contents: [{ role: 'user', parts: [{ text: prompt }] }],
        config: {
          thinkingConfig: { thinkingBudget: 32768 },
          temperature: 0.4,
          seed: 42,
          systemInstruction: `You are MIRA, the interactive Lead RCM Facilitator. You help users build SAE JA1011 compliant strategies. You are expert, professional, and friendly. You always use <ACTION> tags for technical additions in ${language}.`
        }
      });

      const { cleanText, proposals } = parseAIResponse(response.text || "");
      setMessages(prev => [...prev, { 
        role: 'model', 
        text: cleanText || "I've processed your request. See the suggested technical implementation below.", 
        proposals 
      }]);
    } catch (error) {
      setMessages(prev => [...prev, { role: 'model', text: "Facilitator session interrupted." }]);
    } finally {
      setIsLoading(false);
    }
  };

  const applySingleAction = (proposalId: string, messageIndex: number) => {
    setMessages(prevMessages => {
      const message = prevMessages[messageIndex];
      if (!message || !message.proposals) return prevMessages;

      const proposal = message.proposals.find(p => p.id === proposalId);
      if (!proposal || proposal.applied || !proposal.item) return prevMessages;

      let newData = data ? [...data] : [];

      if (proposal.type === 'ADD') {
        const item = proposal.item;

        const getScore = (val: any, def: number) => {
          if (typeof val === 'number') return val;
          if (typeof val === 'string') {
            const match = val.match(/\d+/);
            return match ? parseInt(match[0]) : def;
          }
          return def;
        };

        const s = getScore(item.severity, 5);
        const o = getScore(item.occurrence, 3);
        const d = getScore(item.detection, 4);
        const rpnValue = s * o * d;

        const newItem: RCMItem = {
          id: `rcm-mir-${Date.now()}-${Math.random().toString(36).substr(2, 5)}`,
          component: item.component || 'Synthesized Component',
          functionType: (item.functionType as any) || 'Primary',
          function: item.function || 'Perform primary functional duty.',
          functionalFailure: item.functionalFailure || 'Total loss of primary function.',
          failureMode: item.failureMode || 'Component-level failure mechanism.',
          failureEffect: item.failureEffect || 'Local and system impact.',
          criticality: (item.criticality as any) || (rpnValue >= 100 ? 'High' : rpnValue >= 40 ? 'Medium' : 'Low'),
          consequenceCategory: (item.consequenceCategory as ConsequenceCategory) || 'Evident - Operational',
          iso14224Code: item.iso14224Code || 'OTH',
          severity: s,
          occurrence: o,
          detection: d,
          rpn: rpnValue,
          maintenanceTask: item.maintenanceTask || 'Inspection/Servicing protocol.',
          interval: item.interval || 'Monthly',
          taskType: (item.taskType as any) || 'Condition Monitoring',
          componentIntel: item.componentIntel || {
            description: 'Engineering specifications synthesized from operational context.',
            location: 'Asset-specific installation point.',
            visualCues: 'Standard identification markers.'
          },
          isNew: true,
          isMiraGenerated: true
        };
        newData.push(newItem);
      } 
      else if (proposal.type === 'UPDATE') {
        newData = newData.map(item => {
          const isMatch = proposal.item?.id ? item.id === proposal.item.id : (item.component === proposal.item?.component && item.failureMode === proposal.item?.failureMode);
          if (isMatch) {
            const updated = { ...item, ...proposal.item, isNew: false, isMiraGenerated: true };
            updated.severity = Number(updated.severity) || item.severity;
            updated.occurrence = Number(updated.occurrence) || item.occurrence;
            updated.detection = Number(updated.detection) || item.detection;
            updated.rpn = updated.severity * updated.occurrence * updated.detection;
            return updated as RCMItem;
          }
          return item;
        });
      }

      onUpdate(newData);

      return prevMessages.map((m, idx) => {
        if (idx === messageIndex && m.proposals) {
          return {
            ...m,
            proposals: m.proposals.map(p => p.id === proposalId ? { ...p, applied: true } : p)
          };
        }
        return m;
      });
    });
  };

  return (
    <>
      <div className="fixed bottom-6 right-6 z-40 flex flex-col items-end gap-3 transition-all duration-500">
        <button 
          onClick={() => setIsOpen(!isOpen)}
          className={`flex items-center gap-3 p-4 sm:px-6 sm:py-4 rounded-[1.8rem] shadow-2xl transition-all active:scale-95 border ${isOpen ? 'bg-white text-slate-900 border-slate-100' : 'bg-indigo-600 text-white border-indigo-500 hover:bg-indigo-700'}`}
        >
          <div className={`p-2 rounded-xl ${isOpen ? 'bg-indigo-50 text-indigo-600' : 'bg-white/20'}`}>
            <Zap size={22} className={isOpen ? 'fill-indigo-600' : 'fill-white'} />
          </div>
          <span className="hidden sm:inline text-xs font-black uppercase tracking-widest">{isOpen ? 'Close MIRA' : 'Talk to MIRA'}</span>
        </button>
      </div>

      {isOpen && (
        <div className="fixed bottom-24 right-6 z-40 w-[calc(100vw-3rem)] sm:w-[28rem] h-[36rem] bg-white rounded-[2.5rem] shadow-2xl border border-slate-100 flex flex-col overflow-hidden animate-in slide-in-from-bottom-6 duration-500">
          <div className="bg-slate-900 p-6 flex justify-between items-center text-white shrink-0">
            <div className="flex items-center gap-4">
              <div className="p-3 bg-indigo-500/20 rounded-2xl border border-indigo-500/30">
                <Zap size={20} className="text-indigo-400 fill-indigo-400" />
              </div>
              <div>
                <h3 className="font-black text-lg tracking-tighter uppercase leading-none">MIRA Facilitator</h3>
                <p className="text-[10px] text-indigo-400 font-black uppercase tracking-widest mt-1">Reliability Synthesis AI</p>
              </div>
            </div>
            <div className="flex gap-2">
              <button 
                onClick={() => setMessages([])}
                className="p-2 text-slate-500 hover:text-white transition-colors"
                title="Clear Chat"
              >
                <RotateCcw size={18} />
              </button>
              <button onClick={() => setIsOpen(false)} className="p-2 text-slate-500 hover:text-white transition-colors"><X size={20} /></button>
            </div>
          </div>

          <div className="bg-slate-50 border-b border-slate-100 px-6 py-3 flex justify-between items-center shrink-0">
             <div className="flex items-center gap-2 text-[9px] font-black text-slate-400 uppercase tracking-widest">
               <ShieldAlert size={14} className="text-indigo-600" /> Strategic Hub
             </div>
             <button 
               onClick={handleFacilitatorAudit}
               disabled={!data || data.length === 0 || isLoading}
               className="flex items-center gap-2 px-3 py-1.5 bg-indigo-600 text-white rounded-xl text-[9px] font-black uppercase tracking-widest hover:bg-indigo-700 transition-all disabled:opacity-30 shadow-lg shadow-indigo-100 active:scale-95"
             >
               <Sparkles size={12} /> Run Strategic Audit
             </button>
          </div>

          <div ref={scrollRef} className="flex-1 overflow-y-auto p-6 space-y-6 bg-slate-50/30 custom-scrollbar">
            {messages.length === 0 && (
              <div className="flex flex-col items-center justify-center h-full text-center space-y-4 opacity-50">
                <div className="p-6 bg-white rounded-[2rem] border border-slate-100 shadow-sm">
                  <LayoutGrid size={48} className="text-indigo-100" />
                </div>
                <div>
                  <p className="text-sm font-bold text-slate-800 uppercase tracking-tight">Facilitator Session</p>
                  <p className="text-[10px] font-medium text-slate-400 uppercase tracking-widest mt-1">Ask questions or run strategic reliability audits</p>
                </div>
              </div>
            )}

            {messages.map((m, mIdx) => (
              <div key={mIdx} className={`flex flex-col gap-3 ${m.role === 'user' ? 'items-end' : 'items-start'}`}>
                <div className={`p-4 rounded-2xl shadow-sm text-sm font-medium ${m.role === 'user' ? 'bg-indigo-600 text-white rounded-tr-none' : 'bg-white text-slate-800 border border-slate-100 rounded-tl-none ring-1 ring-slate-50'}`}>
                  <FormattedMessage text={m.text} role={m.role} />
                </div>

                {m.proposals && m.proposals.length > 0 && (
                  <div className="w-full space-y-4 mt-2">
                    {m.proposals.map((p) => {
                      const s = Number(p.item.severity) || 5;
                      const o = Number(p.item.occurrence) || 3;
                      const d = Number(p.item.detection) || 4;
                      const rpnValue = s * o * d;

                      return (
                        <div key={p.id} className={`p-5 rounded-[1.8rem] border bg-white shadow-2xl animate-in zoom-in-95 duration-300 relative overflow-hidden group/card ${p.applied ? 'border-emerald-200 bg-emerald-50/20' : 'border-indigo-100 ring-4 ring-indigo-50/30'}`}>
                          {p.applied && <div className="absolute inset-0 bg-emerald-50/90 backdrop-blur-sm z-10 flex items-center justify-center font-black text-emerald-600 text-[10px] uppercase tracking-[0.3em]"><CheckCircle2 size={16} className="mr-2" /> Synced to Table</div>}

                          <div className="flex items-center gap-3 mb-4">
                             <div className={`p-2 rounded-lg ${p.type === 'ADD' ? 'bg-indigo-600 text-white shadow-md' : 'bg-amber-500 text-white shadow-md'}`}>
                               {p.type === 'ADD' ? <Plus size={14} /> : <RotateCcw size={14} />}
                             </div>
                             <span className="text-[10px] font-black text-slate-900 uppercase tracking-widest">MIRA Recommendation</span>
                          </div>

                          <div className="space-y-4 mb-5">
                             <div className="space-y-1">
                                <div className="flex items-center gap-2 opacity-50">
                                   <Box size={10} className="text-slate-500" />
                                   <span className="text-[9px] font-black uppercase tracking-widest">Component Name</span>
                                </div>
                                <p className="text-xs font-black text-slate-900 uppercase tracking-tighter pl-1">{p.item.component || 'Analyzing...'}</p>
                             </div>

                             <div className="space-y-1">
                                <div className="flex items-center gap-2 opacity-50">
                                   <AlertTriangle size={10} className="text-amber-600" />
                                   <span className="text-[9px] font-black uppercase tracking-widest">Failure Mode</span>
                                </div>
                                <p className="text-[11px] font-bold text-slate-700 leading-tight uppercase tracking-tight pl-1 bg-slate-50/50 p-2 rounded-lg border border-slate-100">{p.item.failureMode}</p>
                             </div>

                             <div className="space-y-1">
                                <div className="flex items-center gap-2 opacity-50">
                                   <ClipboardList size={10} className="text-indigo-600" />
                                   <span className="text-[9px] font-black uppercase tracking-widest">Proposed Task</span>
                                </div>
                                <div className="pl-1 flex flex-col gap-1">
                                   <p className="text-[11px] font-black text-indigo-700 uppercase tracking-tight leading-tight">{p.item.maintenanceTask}</p>
                                   <p className="text-[10px] text-slate-400 font-bold italic">{p.item.interval} • {p.item.taskType}</p>
                                </div>
                             </div>

                             <div className="flex items-center justify-between pt-2 border-t border-slate-100">
                                <div className="flex items-center gap-2">
                                   <Activity size={12} className="text-slate-400" />
                                   <span className="text-[9px] font-black uppercase tracking-widest text-slate-400">RPN Score: {rpnValue}</span>
                                </div>
                                <div className="flex gap-1">
                                   <span className="px-1.5 py-0.5 bg-slate-100 text-slate-600 text-[8px] font-black rounded border border-slate-200 uppercase">{p.item.iso14224Code}</span>
                                   <span className="px-1.5 py-0.5 bg-indigo-50 text-indigo-600 text-[8px] font-black rounded border border-indigo-100 uppercase">{p.item.functionType}</span>
                                </div>
                             </div>
                          </div>

                          {!p.applied && (
                            <button 
                              onClick={() => applySingleAction(p.id, mIdx)}
                              className="w-full py-3 bg-slate-900 text-white rounded-2xl text-[10px] font-black uppercase tracking-widest hover:bg-indigo-600 transition-all flex items-center justify-center gap-3 shadow-xl active:scale-95"
                            >
                              <Plus size={16} /> Implement to Table
                            </button>
                          )}
                        </div>
                      );
                    })}
                  </div>
                )}
              </div>
            ))}

            {isLoading && (
              <div className="flex justify-start">
                <div className="bg-white p-4 rounded-2xl border border-slate-100 shadow-sm flex items-center gap-3 ring-1 ring-slate-50">
                  <Loader2 size={16} className="animate-spin text-indigo-600" />
                  <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest italic">MIRA is synthesizing...</span>
                </div>
              </div>
            )}
          </div>

          <div className="p-6 bg-white border-t border-slate-50 shadow-[0_-10px_30px_rgba(0,0,0,0.02)]">
            <div className="flex gap-3">
              <input 
                type="text" 
                value={input}
                onChange={e => setInput(e.target.value)}
                onKeyDown={e => e.key === 'Enter' && handleSend()}
                placeholder="Talk to your RCM Facilitator..."
                className="flex-1 bg-slate-50 border border-slate-100 rounded-xl px-4 py-3 text-sm focus:bg-white focus:border-indigo-600 focus:ring-4 focus:ring-indigo-100 outline-none transition-all placeholder:text-slate-300 font-medium"
              />
              <button 
                onClick={handleSend}
                disabled={!input.trim() || isLoading}
                className="p-3 bg-slate-900 text-white rounded-xl hover:bg-indigo-600 disabled:opacity-30 transition-all shadow-lg active:scale-95"
              >
                <Send size={20} />
              </button>
            </div>
          </div>
        </div>
      )}
    </>
  );
};

import React, { useState, useMemo } from 'react';
import { RCMItem, InspectionSheet, InspectionStep, ConsequenceCategory, ComponentIntel } from '../types';
import { generateInspectionSheet, generateComponentIntel, validateRCMAnalysis } from '../services/geminiService';
import { IntervalOptimizerModal } from './IntervalOptimizerModal';
import { CMMSBridgeModal } from './CMMSBridgeModal';
import { 
  BarChart, Bar, XAxis, YAxis, CartesianGrid, ResponsiveContainer, Tooltip as RechartsTooltip, Cell 
} from 'recharts';
import { 
  AlertTriangle, CheckCircle, Clock, Activity, FileText, 
  Pencil, Trash2, Save, X, ClipboardList, Loader2,
  FileCheck, File, Printer, AlertOctagon, FilterX, User, ShieldAlert, Wrench, Search, ChevronRight, Sparkles, RefreshCw,
  ArrowUpDown, ArrowUp, ArrowDown, Filter, Plus, Tag, ShieldCheck, Zap, ListChecks, Info, MapPin, Eye, Undo2, Target, Palette, Image as ImageIcon, Box, Layers, UserPlus, Copy, LayoutList, Download, ShieldX
} from 'lucide-react';

interface AnalysisResultProps {
  data: RCMItem[];
  studyName: string;
  onUpdate: (newData: RCMItem[]) => void;
  onUndo: () => void;
  canUndo: boolean;
  language: string;
}

const CONSEQUENCE_LABELS: ConsequenceCategory[] = [
  'Hidden - Safety/Env', 
  'Hidden - Operational', 
  'Evident - Safety/Env', 
  'Evident - Operational',
  'Evident - Non-Operational'
];

const getRPNColorStyle = (rpn: number) => {
  if (rpn >= 120) return { bg: 'bg-red-100', text: 'text-red-900', bar: 'bg-red-500' };
  if (rpn >= 75) return { bg: 'bg-orange-100', text: 'text-orange-900', bar: 'bg-orange-500' };
  if (rpn >= 40) return { bg: 'bg-yellow-50', text: 'text-yellow-800', bar: 'bg-yellow-400' };
  return { bg: 'bg-emerald-50', text: 'text-emerald-800', bar: 'bg-emerald-400' };
};

const getScoreColor = (score: number) => {
  if (score >= 8) return 'text-red-600 font-bold';
  if (score >= 5) return 'text-amber-600 font-medium';
  return 'text-slate-500';
};

export const AnalysisResult: React.FC<AnalysisResultProps> = ({ data, studyName, onUpdate, onUndo, canUndo, language }) => {
  const [editingId, setEditingId] = useState<string | null>(null);
  const [editForm, setEditForm] = useState<RCMItem | null>(null);
  const [matrixFilter, setMatrixFilter] = useState<{s: number, o: number} | null>(null);
  const [barFilter, setBarFilter] = useState<string | null>(null);
  const [selectedIntel, setSelectedIntel] = useState<RCMItem | null>(null);

  const [sortConfig, setSortConfig] = useState<{ key: keyof RCMItem | 'rpn' | 'status_color' | 'inspectionSheet'; direction: 'asc' | 'desc' }>({ key: 'functionType', direction: 'asc' });
  const [searchFilters, setSearchFilters] = useState({
    component: '',
    functionType: '',
    function: '',
    failureMode: '',
    consequenceCategory: '',
    iso14224Code: ''
  });

  const [generatingSheets, setGeneratingSheets] = useState(false);
  const [isValidating, setIsValidating] = useState(false);
  const [generatingIntelIds, setGeneratingIntelIds] = useState<Set<string>>(new Set());
  const [progress, setProgress] = useState({ current: 0, total: 0 });
  const [viewSheet, setViewSheet] = useState<{item: RCMItem} | null>(null);
  const [editingStepIdx, setEditingStepIdx] = useState<number | null>(null);
  const [optimizingItem, setOptimizingItem] = useState<RCMItem | null>(null);
  const [showCMMSBridge, setShowCMMSBridge] = useState(false);
  const [isExtracting, setIsExtracting] = useState(false);

  const [regeneratingIds, setRegeneratingIds] = useState<Set<string>>(new Set());

  const processedData = useMemo(() => {
    let result = (data || []).filter(item => item !== null && item !== undefined);

    if (matrixFilter) {
      result = result.filter(item => 
        (item.severity || 0) === matrixFilter.s && 
        (item.occurrence || 0) === matrixFilter.o
      );
    }

    if (barFilter) {
      result = result.filter(item => item.id === barFilter);
    }

    if (searchFilters.component) {
      result = result.filter(item => (item.component || '').toLowerCase().includes(searchFilters.component.toLowerCase()));
    }
    if (searchFilters.functionType) {
      result = result.filter(item => (item.functionType || '').toLowerCase() === searchFilters.functionType.toLowerCase());
    }
    if (searchFilters.function) {
      result = result.filter(item => (item.function || '').toLowerCase().includes(searchFilters.function.toLowerCase()));
    }
    if (searchFilters.failureMode) {
      result = result.filter(item => (item.failureMode || '').toLowerCase().includes(searchFilters.failureMode.toLowerCase()));
    }
    if (searchFilters.consequenceCategory) {
      result = result.filter(item => (item.consequenceCategory || '').toLowerCase().includes(searchFilters.consequenceCategory.toLowerCase()));
    }
    if (searchFilters.iso14224Code) {
      result = result.filter(item => (item.iso14224Code || '').toLowerCase().includes(searchFilters.iso14224Code.toLowerCase()));
    }

    result.sort((a, b) => {
      const multiplier = sortConfig.direction === 'asc' ? 1 : -1;

      // Hierarchy: FunctionType > FunctionName > FF > Component > FailureMode
      const secondarySort = (x: RCMItem, y: RCMItem) => {
        const ft = (x.functionType || '').localeCompare(y.functionType || '');
        if (ft !== 0) return ft;
        const f = (x.function || '').localeCompare(y.function || '');
        if (f !== 0) return f;
        const ff = (x.functionalFailure || '').localeCompare(y.functionalFailure || '');
        if (ff !== 0) return ff;
        const comp = (x.component || '').localeCompare(y.component || '');
        if (comp !== 0) return comp;
        return (x.failureMode || '').localeCompare(y.failureMode || '');
      };

      if (sortConfig.key === 'status_color') {
        const aVal = (a.isNew ? 1 : 0) * 1000 + (a.rpn || 0);
        const bVal = (b.isNew ? 1 : 0) * 1000 + (b.rpn || 0);
        if (aVal === bVal) return secondarySort(a, b);
        return (bVal - aVal) * multiplier;
      }

      if (sortConfig.key === 'inspectionSheet') {
        const aHas = a.inspectionSheet ? 1 : 0;
        const bHas = b.inspectionSheet ? 1 : 0;
        if (aHas === bHas) return secondarySort(a, b);
        return (aHas - bHas) * multiplier;
      }

      const aVal = a[sortConfig.key as keyof RCMItem];
      const bVal = b[sortConfig.key as keyof RCMItem];

      if (aVal === bVal) return secondarySort(a, b);
      if (aVal === undefined || aVal === null) return 1;
      if (bVal === undefined || bVal === null) return -1;

      if (typeof aVal === 'string' && typeof bVal === 'string') {
        return aVal.localeCompare(bVal) * multiplier;
      }
      return ((aVal as number) - (bVal as number)) * multiplier;
    });

    return result;
  }, [data, matrixFilter, barFilter, sortConfig, searchFilters]);

  const handleInternalUndo = () => {
    onUndo();
    setTimeout(() => {
       if (viewSheet) {
          const updatedItem = data.find(i => i.id === viewSheet.item.id);
          if (updatedItem) setViewSheet({ item: updatedItem });
       }
       if (selectedIntel) {
          const updatedItem = data.find(i => i.id === selectedIntel.id);
          if (updatedItem) setSelectedIntel(updatedItem);
       }
    }, 0);
  };

  const requestSort = (key: keyof RCMItem | 'rpn' | 'status_color' | 'inspectionSheet') => {
    let direction: 'asc' | 'desc' = 'asc';
    if (sortConfig.key === key && sortConfig.direction === 'asc') {
      direction = 'desc';
    } else if (key === 'rpn' || key === 'status_color' || key === 'inspectionSheet') {
      direction = 'desc';
    }
    setSortConfig({ key, direction });
  };

  const handleSearchChange = (field: keyof typeof searchFilters, value: string) => {
    setSearchFilters(prev => ({ ...prev, [field]: value }));
  };

  const handleDelete = (id: string) => {
    const newData = data.filter(item => item.id !== id);
    onUpdate(newData);
    if (viewSheet?.item.id === id) setViewSheet(null);
  };

  const handleEdit = (item: RCMItem) => {
    setEditingId(item.id);
    setEditForm({ ...item });
  };

  const handleCancel = () => {
    setEditingId(null);
    setEditForm(null);
  };

  const handleSave = async () => {
    if (!editForm || !editingId) return;
    const originalItem = data.find(d => d.id === editingId);
    if (!originalItem) return;
    const hasCriticalChanges = 
      editForm.maintenanceTask !== originalItem.maintenanceTask ||
      editForm.failureMode !== originalItem.failureMode ||
      editForm.component !== originalItem.component;
    const needsRegeneration = hasCriticalChanges && !!originalItem.inspectionSheet;
    const updatedForm = {
       ...editForm,
       rpn: (editForm.severity || 1) * (editForm.occurrence || 1) * (editForm.detection || 1),
       inspectionSheet: needsRegeneration ? undefined : editForm.inspectionSheet,
       isNew: false
    };
    const newData = data.map(item => item.id === editingId ? updatedForm : item);
    onUpdate(newData);
    setEditingId(null);
    setEditForm(null);
    if (needsRegeneration) {
      setRegeneratingIds(prev => new Set(prev).add(updatedForm.id));
      try {
        const newSheet = await generateInspectionSheet(updatedForm, language);
        const finalData = newData.map(item => 
          item.id === updatedForm.id ? { ...item, inspectionSheet: newSheet } : item
        );
        onUpdate(finalData);
      } catch (err) { console.error("Failed to auto-regenerate sheet", err); } finally {
        setRegeneratingIds(prev => {
          const next = new Set(prev);
          next.delete(updatedForm.id);
          return next;
        });
      }
    }
  };

  const handleChange = (field: keyof RCMItem, value: any) => {
    if (!editForm) return;
    setEditForm({ ...editForm, [field]: value });
  };

  const handleGenerateAllSheets = async () => {
    const itemsToProcess = data.filter(item => !item.inspectionSheet);
    if (itemsToProcess.length === 0) {
      alert("All items already have inspection sheets generated.");
      return;
    }
    setGeneratingSheets(true);
    setProgress({ current: 0, total: itemsToProcess.length });
    let currentData = [...data];
    const BATCH_SIZE = 3;
    for (let i = 0; i < itemsToProcess.length; i += BATCH_SIZE) {
      const batch = itemsToProcess.slice(i, i + BATCH_SIZE);
      await Promise.all(batch.map(async (item) => {
        try {
          const sheet = await generateInspectionSheet(item, language);
          const index = currentData.findIndex(d => d.id === item.id);
          if (index !== -1) currentData[index] = { ...currentData[index], inspectionSheet: sheet };
        } catch (e) { console.error(e); }
      }));
      setProgress(prev => ({ ...prev, current: Math.min(prev.total, i + BATCH_SIZE) }));
      onUpdate([...currentData]);
    }
    setGeneratingSheets(false);
  };

  const handleValidateLogic = async () => {
    if (data.length === 0) return;
    setIsValidating(true);
    try {
      const issues = await validateRCMAnalysis(data, language);
      const newData = data.map(item => {
        const match = issues.find(issue => issue.id === item.id);
        return { ...item, validationIssues: match ? match.issues : [] };
      });
      onUpdate(newData);
    } catch (e) {
      console.error(e);
      alert("Logic validation engine failed. Please try again.");
    } finally {
      setIsValidating(false);
    }
  };

  const handleIntelClick = async (item: RCMItem) => {
    if (item.componentIntel && item.componentIntel.description) {
      setSelectedIntel(item);
      return;
    }

    setGeneratingIntelIds(prev => new Set(prev).add(item.id));
    try {
      const intel = await generateComponentIntel(item.component, language);
      const newItem = { ...item, componentIntel: intel };
      const newData = data.map(d => d.id === item.id ? newItem : d);
      onUpdate(newData);
      setSelectedIntel(newItem);
    } catch (e) {
      console.error(e);
      alert("Failed to synthesize component metadata.");
    } finally {
      setGeneratingIntelIds(prev => {
        const next = new Set(prev);
        next.delete(item.id);
        return next;
      });
    }
  };

  const handleGenerateSingleSheet = async (item: RCMItem) => {
    setRegeneratingIds(prev => new Set(prev).add(item.id));
    try {
      const sheet = await generateInspectionSheet(item, language);
      const newData = data.map(d => d.id === item.id ? { ...d, inspectionSheet: sheet } : d);
      onUpdate(newData);
      const updatedItem = newData.find(d => d.id === item.id);
      if (updatedItem) setViewSheet({ item: updatedItem });
    } catch (e) { 
      alert("Failed to generate."); 
    } finally { 
      setRegeneratingIds(prev => {
        const next = new Set(prev);
        next.delete(item.id);
        return next;
      });
    }
  };

  const handleApplyOptimizedInterval = (newInterval: string) => {
    if (!optimizingItem) return;
    const newData = data.map(d => d.id === optimizingItem.id ? { ...d, interval: newInterval } : d);
    onUpdate(newData);
    setOptimizingItem(null);
  };

  const updateItemInMainData = (updatedItem: RCMItem) => {
    const newData = data.map(d => d.id === updatedItem.id ? updatedItem : d);
    onUpdate(newData);
  };

  const handleDeleteStep = (idx: number) => {
    if (!viewSheet) return;
    const item = viewSheet.item;
    const sheet = item.inspectionSheet;
    if (!sheet || !sheet.steps) return;
    const newSteps = sheet.steps.filter((_, i) => i !== idx).map((s, i) => ({ ...s, step: i + 1 }));
    const updatedItem = { ...item, inspectionSheet: { ...sheet, steps: newSteps } };
    setViewSheet({ item: updatedItem });
    updateItemInMainData(updatedItem);
  };

  const handleAddStep = () => {
    if (!viewSheet) return;
    const item = viewSheet.item;
    const sheet = item.inspectionSheet || { responsibility: 'Operator', estimatedTime: '10m', safetyPrecautions: 'Standard PPE', toolsRequired: 'None', steps: [] };
    const newStep: InspectionStep = {
      step: (sheet.steps?.length || 0) + 1,
      description: 'New inspection action',
      criteria: 'Pass/Fail criteria',
      technique: 'Visual'
    };
    const updatedItem = { ...item, inspectionSheet: { ...sheet, steps: [...(sheet.steps || []), newStep] } };
    setViewSheet({ item: updatedItem });
    updateItemInMainData(updatedItem);
    setEditingStepIdx((sheet.steps?.length || 0));
  };

  const handleUpdateStepField = (idx: number, field: keyof InspectionStep, value: string | number) => {
    if (!viewSheet) return;
    const item = viewSheet.item;
    const sheet = item.inspectionSheet;
    if (!sheet || !sheet.steps) return;
    const newSteps = [...sheet.steps];
    newSteps[idx] = { ...newSteps[idx], [field]: value };
    const updatedItem = { ...item, inspectionSheet: { ...sheet, steps: newSteps } };
    setViewSheet({ item: updatedItem });
    updateItemInMainData(updatedItem);
  };

  const handleExcelTechnicalExtract = () => {
    setIsExtracting(true);
    const headers = [
      "Function", 
      "Functional failure", 
      "Component", 
      "Component Description",
      "Failure mode", 
      "ISO 14224 Code",
      "Proposed Task", 
      "Frequency",
      "Step", 
      "Action",
      "Responsibility",
      "Duration",
      "Acceptance Criteria"
    ];

    const rows: string[] = [];

    let lastFunc = "";
    let lastFF = "";
    let lastComp = "";
    let lastFM = "";

    // Sort by RCM hierarchy for the export but use filtered data to respect active search/filters
    const sortedForExport = [...processedData].sort((a, b) => {
        const ft = (a.functionType || '').localeCompare(b.functionType || '').toLocaleString();
        if (ft !== '0') return ft.localeCompare('0');
        const f = (a.function || '').localeCompare(b.function || '').toLocaleString();
        if (f !== '0') return f.localeCompare('0');
        const ff = (a.functionalFailure || '').localeCompare(b.functionalFailure || '').toLocaleString();
        if (ff !== '0') return ff.localeCompare('0');
        const comp = (a.component || '').localeCompare(b.component || '').toLocaleString();
        if (comp !== '0') return comp.localeCompare('0');
        return (a.failureMode || '').localeCompare(b.failureMode || '');
    });

    sortedForExport.forEach(item => {
      const steps = item.inspectionSheet?.steps || [];
      const responsibility = item.inspectionSheet?.responsibility || "";
      const duration = item.inspectionSheet?.estimatedTime || "";

      // Logic to detect if we should show header cells or keep them empty (Classical RCM sheet style)
      const showFunc = item.function !== lastFunc;
      const showFF = showFunc || item.functionalFailure !== lastFF;
      const showComp = showFF || item.component !== lastComp;
      const showFM = showComp || item.failureMode !== lastFM;

      // Update state for next item
      lastFunc = item.function;
      lastFF = item.functionalFailure;
      lastComp = item.component;
      lastFM = item.failureMode;

      const metadataCols = [
        showFunc ? item.function : "",
        showFF ? item.functionalFailure : "",
        showComp ? item.component : "",
        showComp ? (item.componentIntel?.description || "") : "",
        showFM ? item.failureMode : "",
        showFM ? item.iso14224Code : ""
      ];

      if (steps.length > 0) {
        steps.forEach((step, idx) => {
          // Task and Frequency only show on the first step of this task
          const taskInfo = idx === 0 ? [item.maintenanceTask, item.interval] : ["", ""];
          // Header info (Function -> FM) only show on the first step of the first task of this FM
          const headerInfo = (idx === 0 && showFM) ? metadataCols : ["", "", "", "", "", ""];

          const rowData = [
            ...headerInfo,
            ...taskInfo,
            step.step,
            step.description,
            idx === 0 ? responsibility : "",
            idx === 0 ? duration : "",
            step.criteria
          ];

          rows.push(rowData.map(v => `"${String(v || '').replace(/"/g, '""')}"`).join(","));
        });
      } else {
        // Fallback for items without inspection sheets
        const rowData = [
          showFM ? item.function : "",
          showFF ? item.functionalFailure : "",
          showComp ? item.component : "",
          showComp ? (item.componentIntel?.description || "") : "",
          showFM ? item.failureMode : "",
          showFM ? item.iso14224Code : "",
          item.maintenanceTask,
          item.interval,
          "", "", "", "", ""
        ];
        rows.push(rowData.map(v => `"${String(v || '').replace(/"/g, '""')}"`).join(","));
      }
    });

    const csvContent = "\uFEFFsep=,\n" + [headers.join(","), ...rows].join("\n");
    const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.setAttribute('href', url);

    // Use the studyName for the filename as requested
    const fileNameBase = studyName ? studyName.trim().replace(/\s+/g, '_') : 'RCM_Decision_Sheet';
    link.setAttribute('download', `${fileNameBase}_Decision_Sheet.csv`);

    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);

    setTimeout(() => setIsExtracting(false), 1500);
  };

  const handleMatrixClick = (s: number, o: number) => {
    if (matrixFilter?.s === s && matrixFilter?.o === o) {
      setMatrixFilter(null);
    } else {
      setMatrixFilter({ s, o });
    }
  };

  const handleBarClick = (id: string) => {
    if (barFilter === id) {
      setBarFilter(null);
    } else {
      setBarFilter(id);
    }
  };

  const clearAllFilters = () => {
    setMatrixFilter(null);
    setBarFilter(null);
    setSearchFilters({ component: '', functionType: '', function: '', failureMode: '', consequenceCategory: '', iso14224Code: '' });
    setSortConfig({ key: 'functionType', direction: 'asc' });
  };

  const topRisks = data
    .sort((a, b) => (b.rpn || 0) - (a.rpn || 0))
    .slice(0, 5)
    .map(item => ({
      id: item.id,
      name: (item.failureMode || '').length > 20 ? (item.failureMode || '').substring(0, 20) + '...' : (item.failureMode || ''),
      rpn: item.rpn || 0
    }));

  const renderSortIcon = (key: keyof RCMItem | 'rpn' | 'status_color' | 'inspectionSheet') => {
    if (sortConfig.key !== key) return <ArrowUpDown size={14} className="text-slate-300" />;
    return sortConfig.direction === 'asc' ? <ArrowUp size={14} className="text-indigo-600" /> : <ArrowDown size={14} className="text-indigo-600" />;
  };

  const renderInspectionSheet = () => {
    if (!viewSheet) return null;
    const item = viewSheet.item;
    const sheet = item.inspectionSheet;
    if (!sheet) return null;
    const isRegenerating = regeneratingIds.has(item.id);

    return (
      <div className="fixed inset-0 z-[60] flex items-center justify-center bg-black/60 backdrop-blur-sm p-4 animate-in fade-in duration-200">
        <div className="bg-white rounded-3xl shadow-2xl w-full max-w-7xl overflow-hidden flex flex-col animate-in zoom-in-95 duration-200 border border-slate-100 max-h-[95vh]">
          {/* Header */}
          <div className="bg-slate-900 px-10 py-8 flex justify-between items-center text-white shrink-0">
            <div className="flex items-center gap-6">
              <div className="p-4 bg-emerald-500/20 rounded-[1.5rem] border border-emerald-500/30 shadow-inner">
                <FileCheck size={32} className="text-emerald-200" />
              </div>
              <div>
                <h3 className="font-black text-2xl tracking-tighter uppercase leading-none">Maintenance Inspection Protocol</h3>
                <div className="flex items-center gap-3 mt-2.5">
                   <span className="text-[10px] text-slate-400 font-black uppercase tracking-[0.2em]">{item.component}</span>
                   <div className="w-1 h-1 rounded-full bg-slate-700"></div>
                   <span className="text-[10px] text-emerald-400 font-black uppercase tracking-[0.2em]">Validated Asset Route</span>
                </div>
              </div>
            </div>
            <div className="flex items-center gap-4">
              <button
                onClick={handleInternalUndo}
                disabled={!canUndo}
                className={`p-3 rounded-full transition-all ${
                  canUndo ? 'bg-white/10 text-white hover:bg-white/20' : 'text-slate-600 opacity-20'
                }`}
                title="Undo last action"
              >
                <Undo2 size={28} />
              </button>
              <button onClick={() => setViewSheet(null)} className="p-3 bg-white/5 text-slate-400 hover:bg-white/10 hover:text-white rounded-full transition-all">
                <X size={28} />
              </button>
            </div>
          </div>

          <div className="p-10 overflow-y-auto custom-scrollbar flex-1 bg-slate-50/50">
            <div className="bg-white p-8 rounded-[1.8rem] border border-slate-200 shadow-sm mb-6">
              <div className="grid grid-cols-1 lg:grid-cols-4 gap-8">
                <div>
                  <div className="flex items-center gap-3 mb-2 opacity-60">
                     <Tag size={14} className="text-indigo-600" />
                     <span className="text-[9px] font-black uppercase tracking-widest">Component</span>
                  </div>
                  <p className="text-sm font-black text-slate-900 uppercase tracking-tight">{item.component}</p>
                </div>
                <div>
                  <div className="flex items-center gap-3 mb-2 opacity-60">
                     <AlertTriangle size={14} className="text-amber-600" />
                     <span className="text-[9px] font-black uppercase tracking-widest">Failure Mode</span>
                  </div>
                  <p className="text-xs font-bold text-slate-700 leading-tight uppercase">{item.failureMode}</p>
                </div>
                <div>
                  <div className="flex items-center gap-3 mb-2 opacity-60">
                     <Target size={14} className="text-emerald-600" />
                     <span className="text-[9px] font-black uppercase tracking-widest">Proposed Task</span>
                  </div>
                  <p className="text-xs font-bold text-slate-700 leading-tight uppercase">{item.maintenanceTask}</p>
                </div>
                <div>
                  <div className="flex items-center gap-3 mb-2 opacity-60">
                     <RefreshCw size={14} className="text-indigo-600" />
                     <span className="text-[9px] font-black uppercase tracking-widest">Frequency</span>
                  </div>
                  <p className="text-xs font-black text-indigo-700 uppercase tracking-tight">{item.interval}</p>
                </div>
              </div>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-4 gap-6 mb-10">
              <div className="bg-white p-6 rounded-[1.8rem] border border-slate-100 shadow-sm">
                <div className="flex items-center gap-3 mb-2 opacity-60">
                   <User size={14} className="text-slate-900" />
                   <span className="text-[9px] font-black uppercase tracking-widest">Responsibility</span>
                </div>
                <p className="text-sm font-black text-slate-900 uppercase tracking-tight">{sheet.responsibility}</p>
              </div>
              <div className="bg-white p-6 rounded-[1.8rem] border border-slate-100 shadow-sm">
                <div className="flex items-center gap-3 mb-2 opacity-60">
                   <Clock size={14} className="text-slate-900" />
                   <span className="text-[9px] font-black uppercase tracking-widest">Est. Duration</span>
                </div>
