  /**
   * Helper to clean strings for CSV export to ensure 
   * compatibility with Excel in all 5 target languages.
   */
  const cleanStrForCSV = (val: any): string => {
    if (val === null || val === undefined) return '';
    const str = String(val);

    // 1. Replace newlines, tabs and carriage returns with spaces 
    // to prevent row breaks in CSV.
    // 2. Remove non-printable control characters (\x00-\x1F, \x7F-\x9F).
    // 3. Keep standard and extended Latin characters (accented chars like ñ, ł, ö, é).
    const cleaned = str
      .replace(/[\n\r\t]/g, ' ')
      .replace(/[\x00-\x1F\x7F-\x9F]/g, '')
      .trim();

    // 4. Escape double quotes for CSV standard
    return cleaned.replace(/"/g, '""');
  };

  const handleExcelTechnicalExtract = () => {
    setIsExtracting(true);
    const headers = [
      "Function", 
      "Functional failure", 
      "Component", 
      "Component Description",
      "Failure mode", 
      "ISO 14224 Code",
      "Proposed Task", 
      "Frequency",
      "Step", 
      "Action",
      "Responsibility",
      "Duration",
      "Acceptance Criteria"
    ];

    const rows: string[] = [];

    let lastFunc = "";
    let lastFF = "";
    let lastComp = "";
    let lastFM = "";

    // Sort by RCM hierarchy for the export but use filtered data to respect active search/filters
    const sortedForExport = [...processedData].sort((a, b) => {
        const ft = (a.functionType || '').localeCompare(b.functionType || '').toLocaleString();
        if (ft !== '0') return ft.localeCompare('0');
        const f = (a.function || '').localeCompare(b.function || '').toLocaleString();
        if (f !== '0') return f.localeCompare('0');
        const ff = (a.functionalFailure || '').localeCompare(b.functionalFailure || '').toLocaleString();
        if (ff !== '0') return ff.localeCompare('0');
        const comp = (a.component || '').localeCompare(b.component || '').toLocaleString();
        if (comp !== '0') return comp.localeCompare('0');
        return (a.failureMode || '').localeCompare(b.failureMode || '');
    });

    sortedForExport.forEach(item => {
      const steps = item.inspectionSheet?.steps || [];
      const responsibility = item.inspectionSheet?.responsibility || "";
      const duration = item.inspectionSheet?.estimatedTime || "";

      // Logic to detect if we should show header cells or keep them empty (Classical RCM sheet style)
      const showFunc = item.function !== lastFunc;
      const showFF = showFunc || item.functionalFailure !== lastFF;
      const showComp = showFF || item.component !== lastComp;
      const showFM = showComp || item.failureMode !== lastFM;

      // Update state for next item
      lastFunc = item.function;
      lastFF = item.functionalFailure;
      lastComp = item.component;
      lastFM = item.failureMode;

      const metadataCols = [
        showFunc ? item.function : "",
        showFF ? item.functionalFailure : "",
        showComp ? item.component : "",
        showComp ? (item.componentIntel?.description || "") : "",
        showFM ? item.failureMode : "",
        showFM ? item.iso14224Code : ""
      ];

      if (steps.length > 0) {
        steps.forEach((step, idx) => {
          // Task and Frequency only show on the first step of this task
          const taskInfo = idx === 0 ? [item.maintenanceTask, item.interval] : ["", ""];
          // Header info (Function -> FM) only show on the first step of the first task of this FM
          const headerInfo = (idx === 0 && showFM) ? metadataCols : ["", "", "", "", "", ""];

          const rowData = [
            ...headerInfo,
            ...taskInfo,
            step.step,
            step.description,
            idx === 0 ? responsibility : "",
            idx === 0 ? duration : "",
            step.criteria
          ];

          rows.push(rowData.map(v => `"${cleanStrForCSV(v)}"`).join(","));
        });
      } else {
        // Fallback for items without inspection sheets
        const rowData = [
          showFM ? item.function : "",
          showFF ? item.functionalFailure : "",
          showComp ? item.component : "",
          showComp ? (item.componentIntel?.description || "") : "",
          showFM ? item.failureMode : "",
          showFM ? item.iso14224Code : "",
          item.maintenanceTask,
          item.interval,
          "", "", "", "", ""
        ];
        rows.push(rowData.map(v => `"${cleanStrForCSV(v)}"`).join(","));
      }
    });

    // Use BOM \uFEFF for Excel to recognize UTF-8 encoding correctly across languages
    const csvContent = "\uFEFFsep=,\n" + [headers.map(h => `"${h}"`).join(","), ...rows].join("\n");
    const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.setAttribute('href', url);

    // Use the studyName for the filename
    const fileNameBase = studyName ? studyName.trim().replace(/[^a-zA-Z0-9]/g, '_') : 'RCM_Decision_Sheet';
    link.setAttribute('download', `${fileNameBase}_Decision_Sheet.csv`);

    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);

    setTimeout(() => setIsExtracting(false), 1500);
  };

