          <p style="color: #64748b;">${new Date().toLocaleDateString(targetLang)} | SAE JA1011 Reliability Compliance Report</p>
        </div>
    `;

    // Group items for a logical document flow
    const grouped: Record<string, Record<string, RCMItem[]>> = {};
