    Object.entries(grouped).forEach(([funcName, failures]) => {
      htmlContent += `<h1>${labels.func}: ${funcName}</h1>`;

      Object.entries(failures).forEach(([ffName, items]) => {
        htmlContent += `<h2>${labels.ff}: ${ffName}</h2>`;

