          }

          htmlContent += `</div><hr style="border: 0; border-top: 1px solid #e2e8f0; margin: 40px 0;">`;
        });
      });
    });

    htmlContent += `</body></html>`;

    const blob = new Blob([htmlContent], { type: 'application/msword' });
    const url = URL.createObjectURL(blob);
