                        <td className="px-6 py-4 align-top"><select value={editForm.componentType} onChange={(e) => handleChange('componentType', e.target.value)} className="w-full px-2 py-1 border rounded text-[10px] font-black uppercase"><option value="Electrical">Electrical</option><option value="Mechanical">Mechanical</option></select></td>
                        <td className="px-6 py-4 align-top">
                          <select 
                            value={editForm.consequenceCategory} 
                            onChange={(e) => handleChange('consequenceCategory', e.target.value)}
                            className="w-full px-2 py-1 border rounded text-xs"
                          >
                            {CONSEQUENCE_LABELS.map(cat => <option key={cat} value={cat}>{cat}</option>)}
                          </select>
                        </td>
                        <td className="px-6 py-4 align-top"><div className="space-y-2"><textarea rows={2} value={editForm.failureMode} onChange={(e) => handleChange('failureMode', e.target.value)} className="w-full px-2 py-1 border rounded" /><textarea rows={3} value={editForm.failureEffect} onChange={(e) => handleChange('failureEffect', e.target.value)} className="w-full px-2 py-1 border rounded" /></div></td>
                        <td className="px-2 py-4 align-top bg-white/50 border-l"><input type="number" min="1" max="10" value={editForm.severity} onChange={(e) => handleChange('severity', parseInt(e.target.value))} className="w-full text-center border rounded" /></td>
                        <td className="px-2 py-4 align-top bg-white/50"><input type="number" min="1" max="10" value={editForm.occurrence} onChange={(e) => handleChange('occurrence', parseInt(e.target.value))} className="w-full text-center border rounded" /></td>
                        <td className="px-2 py-4 align-top bg-white/50"><input type="number" min="1" max="10" value={editForm.detection} onChange={(e) => handleChange('detection', parseInt(e.target.value))} className="w-full text-center border rounded" /></td>
                        <td className="px-4 py-4 align-top text-center font-bold bg-white/50 border-r">{(editForm.severity || 1) * (editForm.occurrence || 1) * (editForm.detection || 1)}</td>
                        <td className="px-6 py-4 align-top"><div className="space-y-2"><textarea rows={3} value={editForm.maintenanceTask} onChange={(e) => handleChange('maintenanceTask', e.target.value)} className="w-full border rounded" /><input type="text" value={editForm.interval} onChange={(e) => handleChange('interval', e.target.value)} className="w-full border rounded" /></div></td>
                        <td className="px-6 py-4 align-top text-center text-slate-300"><File size={20} className="mx-auto" /></td>
                        <td className="px-6 py-4 align-top text-right"><div className="flex flex-col gap-2 items-end"><button onClick={handleSave} className="p-2 bg-emerald-500 text-white rounded"><Save size={16} /></button><button onClick={handleCancel} className="p-2 bg-slate-200 text-slate-600 rounded"><X size={16} /></button></div></td>
                      </tr>
                    );
                  }
                  const rpn = item.rpn || 0; const rpnStyle = getRPNColorStyle(rpn);
                  const consCat = item.consequenceCategory || '';
                  const isNew = item.isNew === true;
                  const isMiraGenerated = item.isMiraGenerated === true;
                  const isPrimary = item.functionType === 'Primary';
                  const isApproved = item.isApproved === true;

                  return (
                    <tr key={item.id} className={`group hover:bg-slate-50 ${isRegenerating || isGeneratingIntel ? 'opacity-60 bg-slate-50' : ''} ${barFilter === item.id ? 'bg-indigo-50/50' : ''} ${isMiraGenerated ? 'bg-blue-50/80 border-l-4 border-l-blue-500' : isNew ? 'bg-emerald-50/60' : ''} transition-all duration-300 ${hasIssues ? 'border-l-4 border-l-red-500 bg-red-50/20' : ''}`}>
                      <td className="px-4 py-4 align-middle text-center">
                        <button 
                          onClick={() => handleToggleApproved(item.id)}
                          className={`w-6 h-6 rounded-full border-2 transition-all flex items-center justify-center ${isApproved ? 'bg-emerald-500 border-emerald-500 text-white shadow-md shadow-emerald-200 scale-110' : 'bg-white border-slate-200 text-transparent hover:border-emerald-300 hover:text-emerald-300'}`}
                          title={isApproved ? "Approved" : "Mark as Approved"}
                        >
                          <Check size={14} strokeWidth={4} />
                        </button>
                      </td>
                      <td className="px-6 py-4 align-top">
                        {showFunctionType ? (
                          <span className={`text-[10px] font-black uppercase tracking-widest px-2 py-1 rounded-md border ${isPrimary ? 'bg-slate-900 text-white border-slate-900 shadow-sm' : 'bg-white text-slate-400 border-slate-200'}`}>
                            {item.functionType}
                          </span>
                        ) : null}
                      </td>
                      <td className={`px-6 py-4 align-top text-[11px] leading-tight ${isPrimary ? 'text-slate-900 font-black uppercase' : 'text-slate-600 font-bold'}`}>
                        {showFunction ? item.function : null}
                      </td>
                      <td className="px-6 py-4 align-top text-[11px] leading-tight text-slate-600 italic">
                        {showFunctionalFailure ? item.functionalFailure : null}
                      </td>
                      <td className="px-6 py-4 font-medium align-top leading-tight text-xs">
                        {showComponent ? (
                          <div className="flex items-center gap-2">
                            <span className="flex-1 text-slate-700">{item.component}</span>
                            <button 
                              onClick={() => handleIntelClick(item)} 
                              disabled={isGeneratingIntel}
                              className={`p-1.5 rounded-full border transition-all flex items-center justify-center shrink-0 ${
                                isGeneratingIntel 
                                  ? 'bg-amber-50 text-amber-500 border-amber-200 cursor-wait' 
                                  : item.componentIntel && item.componentIntel.description
                                    ? 'text-indigo-500 border-indigo-100 hover:bg-indigo-50 opacity-0 group-hover:opacity-100'
                                    : 'bg-amber-100 text-amber-600 border-amber-300 hover:bg-amber-200 hover:scale-110 shadow-sm'
                              }`} 
                              title={item.componentIntel?.description ? "Component Intelligence" : "Synthesize Physical Intel"}
                            >
                              {isGeneratingIntel ? <RefreshCw size={12} className="animate-spin" /> : <Info size={14} />}
                            </button>
                          </div>
                        ) : null}
                      </td>
                      <td className="px-6 py-4 align-top">
                        {showComponent ? (
                          <span className={`text-[9px] font-black uppercase px-2 py-0.5 rounded border ${item.componentType === 'Electrical' ? 'bg-yellow-50 text-yellow-700 border-yellow-200' : 'bg-blue-50 text-blue-700 border-blue-200'}`}>
                            {item.componentType}
                          </span>
                        ) : null}
                      </td>
                      <td className="px-6 py-4 align-top">
                        <span className={`text-[10px] font-bold px-1.5 py-0.5 rounded-full border ${consCat.includes('Hidden') ? 'bg-orange-50 text-orange-700 border-orange-200' : 'bg-blue-50 text-blue-700 border-blue-200'}`}>
                          {consCat}
                        </span>
                      </td>
                      <td className="px-6 py-4 align-top">
                        <div className="space-y-2">
                          <div className="flex items-start gap-2">
                            <div className="font-semibold text-[11px] border p-1 rounded inline-block bg-white shadow-sm leading-tight flex-1">
                              {item.failureMode}
                            </div>
                            {hasIssues && (
                              <div className="group/issue relative shrink-0 mt-0.5 cursor-help">
                                <ShieldX size={18} className="text-red-500 animate-pulse" />
                                <div className="absolute right-0 top-6 w-64 bg-slate-900 text-white p-3 rounded-xl text-[10px] font-bold shadow-2xl z-50 opacity-0 group-hover/issue:opacity-100 transition-opacity pointer-events-none">
                                  <div className="flex items-center gap-2 mb-2 text-red-400">
                                    <AlertOctagon size={12} />
                                    <span className="uppercase tracking-widest">Logic Violation</span>
                                  </div>
                                  <ul className="space-y-1.5">
                                    {item.validationIssues?.map((issue, i) => (
                                      <li key={i} className="flex gap-2">
                                        <ChevronRight size={10} className="shrink-0 mt-0.5 text-indigo-400" />
                                        <span>{issue}</span>
                                      </li>
                                    ))}
                                  </ul>
                                </div>
                              </div>
                            )}
                          </div>
                          <div className="text-slate-500 text-[10px] leading-relaxed line-clamp-2">{item.failureEffect}</div>
                        </div>
                      </td>
                      <td className="px-2 py-4 align-middle text-center border-l"><span className={getScoreColor(item.severity || 0)}>{item.severity || 0}</span></td>
                      <td className="px-2 py-4 align-middle text-center"><span className={getScoreColor(item.occurrence || 0)}>{item.occurrence || 0}</span></td>
                      <td className="px-2 py-4 align-middle text-center"><span className={getScoreColor(item.detection || 0)}>{item.detection || 0}</span></td>
                      <td className="px-4 py-4 align-middle border-r"><div className="flex flex-col gap-1"><span className={`text-xs font-bold ${rpnStyle.text}`}>{rpn}</span><div className="w-full h-1 bg-slate-100 rounded-full overflow-hidden"><div className={`h-full ${rpnStyle.bar}`} style={{width: `${Math.min((rpn/400)*100, 100)}%`}}></div></div></div></td>
                      <td className="px-6 py-4 align-top group/interval">
                        <div className="font-medium text-xs leading-tight">
                           {item.maintenanceTask}
                           {(item.taskType === 'Training' || item.taskType === 'Procedural Change') && (
                             <span className="ml-2 px-1.5 py-0.5 bg-purple-50 text-purple-600 text-[8px] font-black uppercase rounded border border-purple-100">Human Factor Fix</span>
                           )}
                        </div>
                        <button 
                          onClick={() => setOptimizingItem(item)}
                          className="text-[10px] text-slate-400 font-mono mt-1 hover:text-indigo-600 hover:bg-indigo-50 px-1.5 py-0.5 rounded transition-all flex items-center gap-1 group-hover/interval:border group-hover/interval:border-indigo-100"
                        >
                          <Target size={10} className="opacity-0 group-hover/interval:opacity-100" />
                          {item.interval}
                        </button>
                      </td>
                      <td className="px-6 py-4 align-middle text-center">
                         {isRegenerating ? <RefreshCw size={20} className="animate-spin text-indigo-500 mx-auto" /> : item.inspectionSheet ? <button onClick={() => setViewSheet({ item })} className="text-emerald-500 hover:scale-110 transition-transform"><FileCheck size={22} /></button> : <button onClick={() => handleGenerateSingleSheet(item)} className="text-slate-300 hover:text-indigo-500"><File size={22} /></button>}
                      </td>
                      <td className="px-6 py-4 align-middle text-right opacity-0 group-hover:opacity-100 transition-opacity"><div className="flex justify-end gap-1"><button onClick={() => handleEdit(item)} className="p-1 text-slate-400 hover:text-indigo-600"><Pencil size={16} /></button><button onClick={() => handleDelete(item.id)} className="p-1 text-slate-400 hover:text-red-600"><Trash2 size={16} /></button></div></td>
                    </tr>
                  );
                })
              )}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
};

import { GoogleGenAI } from "@google/genai";
import React, { useState, useRef, useEffect } from 'react';
import { RCMItem, ConsequenceCategory } from '../types';
import { 
  X, Send, Sparkles, ChevronDown, 
  Plus, CheckCircle2, Search, 
  UserCheck, ShieldAlert, Zap, Loader2, LayoutGrid, 
  ChevronRight, RotateCcw, Target, Info, AlertTriangle, Wrench, Box, Activity, FileText, ClipboardList, Database, ShieldX, ClipboardCheck
} from 'lucide-react';

interface AICopilotProps {
  data: RCMItem[] | null;
  onUpdate: (newData: RCMItem[]) => void;
  language: string;
}

interface ProposedAction {
  id: string; 
  type: 'ADD' | 'UPDATE' | 'DELETE';
  item: Partial<RCMItem>;
  reason: string;
  applied?: boolean;
}

interface Message {
  role: 'user' | 'model';
  text: string;
  proposals?: ProposedAction[];
  isFacilitatorInsight?: boolean;
}

const FormattedMessage: React.FC<{ text: string; role: 'user' | 'model'; isFacilitator?: boolean }> = ({ text, role }) => {
  const lines = (text || '').split('\n');

  return (
    <div className={`space-y-2 ${role === 'model' ? 'text-slate-700' : 'text-white'}`}>
      {lines.map((line, idx) => {
        const trimmed = line.trim();
        const cleanLine = line.replace(/\*\*/g, '').replace(/#/g, '').trim();
        if (!cleanLine) return <div key={idx} className="h-2" />;

        const isQuestion = cleanLine.endsWith('?');

        if (trimmed.startsWith('* ') || trimmed.startsWith('- ')) {
          return (
            <div key={idx} className="flex gap-2 pl-2">
              <ChevronRight size={12} className={`shrink-0 mt-1 ${role === 'model' ? 'text-indigo-400' : 'text-white opacity-50'}`} />
              <span className={`flex-1 text-[13px] font-medium leading-relaxed ${isQuestion ? 'text-indigo-700 font-bold italic' : ''}`}>
                {cleanLine.replace(/^[*|-]\s*/, '')}
              </span>
            </div>
          );
        }

        return (
          <p key={idx} className={`leading-relaxed text-[13px] font-medium ${isQuestion && role === 'model' ? 'bg-indigo-50 p-2 rounded-lg border-l-4 border-indigo-600 text-indigo-900 shadow-sm' : ''}`}>
            {cleanLine}
          </p>
        );
      })}
    </div>
  );
};

export const AICopilot: React.FC<AICopilotProps> = ({ data, onUpdate, language }) => {
  const [isOpen, setIsOpen] = useState(false);
  const [input, setInput] = useState('');
  const [messages, setMessages] = useState<Message[]>([]);
  const [isLoading, setIsLoading] = useState(false);

  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (isOpen && scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [isOpen, messages, isLoading]);

  const parseAIResponse = (text: string): { cleanText: string, proposals?: ProposedAction[] } => {
    const actionRegex = /<ACTION>([\s\S]*?)<\/ACTION>/gi;
    const proposals: ProposedAction[] = [];
    let match;

    while ((match = actionRegex.exec(text)) !== null) {
      try {
        let content = match[1].trim();
        // Remove markdown wrappers
        content = content.replace(/^```json\s*/i, '').replace(/\s*```$/i, '').trim();

        // Handle cases where model might wrap in parentheses
        if (content.startsWith('(') && content.endsWith(')')) {
          content = content.substring(1, content.length - 1);
        }

        const raw = JSON.parse(content);
        const actions = Array.isArray(raw) ? raw : [raw];

        actions.forEach((a: any) => {
          if (a && typeof a === 'object') {
            // Check if the structure is nested or flat
            const itemData = a.item || a.data || (a.component ? a : null);
            if (itemData && (itemData.component || itemData.failureMode)) {
              proposals.push({
                id: `proposal-${Math.random().toString(36).substr(2, 9)}`,
                type: (a.type as any) || 'ADD',
                reason: a.reason || 'Strategic reliability enhancement recommendation.',
                item: itemData,
                applied: false
              });
            }
          }
        });
      } catch (e) {
        console.error("MIRA Extraction Error: Tag found but JSON invalid.", e);
      }
    }

    const textWithoutActions = text.replace(/<ACTION>[\s\S]*?<\/ACTION>/gi, '').trim();
    return { cleanText: textWithoutActions, proposals: proposals.length > 0 ? proposals : undefined };
  };

  const RCM_FIELDS_PROMPT = `
    The JSON object MUST include ALL these technical fields:
    - component (string)
    - componentType (string: 'Electrical' or 'Mechanical')
    - functionType (string: 'Primary' or 'Secondary')
    - function (string)
    - functionalFailure (string)
    - failureMode (string)
    - failureEffect (string)
    - consequenceCategory (string: 'Hidden - Safety/Env', 'Hidden - Operational', 'Evident - Safety/Env', 'Evident - Operational', 'Evident - Non-Operational')
    - iso14224Code (string: 3-letter code like BRD, LOP, VIB)
    - severity (number: 1-10)
    - occurrence (number: 1-10)
    - detection (number: 1-10)
    - maintenanceTask (string)
    - interval (string)
    - taskType (string: 'Condition Monitoring', 'Time-Based', 'Run-to-Failure', 'Redesign', 'Failure Finding', 'Lubrication', 'Servicing', 'Restoration', 'Replacement', 'Training', 'Procedural Change')
  `;

  const handleFacilitatorAudit = async () => {
    if (!data || data.length === 0) return;
    setIsLoading(true);

    try {
      // Fix: Initialize GoogleGenAI strictly using process.env.API_KEY
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const studySummary = data.slice(-30).map(i => ({
        comp: i.component,
        fail: i.failureMode,
        task: i.maintenanceTask,
        rpn: i.rpn
      }));

      const prompt = `
        MIRA FACILITATOR STRATEGIC AUDIT.
        Asset Study Context: ${JSON.stringify(studySummary)}
        Target Language: ${language}

        OBJECTIVE:
        1. Critically evaluate the current maintenance strategy.
        2. Identify EXACTLY 3 technical gaps or missed failure modes that are critical for this asset class.
        3. For each gap, you MUST generate a complete RCM record wrapped in <ACTION> tags.

        CRITICAL RULES:
        - DO NOT just say "the study is good". You MUST find missing items.
        - Every recommendation MUST be an <ACTION> block containing a valid JSON object.

        ${RCM_FIELDS_PROMPT}

        Technical descriptions and tasks in the JSON MUST be in ${language}.
      `;

      const response = await ai.models.generateContent({
        model: 'gemini-3-pro-preview',
        contents: [{ role: 'user', parts: [{ text: prompt }] }],
        config: {
          thinkingConfig: { thinkingBudget: 32768 },
          temperature: 0.4,
          seed: 42,
          systemInstruction: `You are MIRA, the Lead RCM Facilitator. You are technical, rigorous, and proactive. Your primary job during an audit is to provide actionable <ACTION> blocks for missing failure modes in ${language}.`
        }
      });

      const { cleanText, proposals } = parseAIResponse(response.text || "");
      setMessages(prev => [...prev, { 
        role: 'model', 
        text: cleanText || "Strategic audit complete. Recommendations generated below.", 
        proposals, 
        isFacilitatorInsight: true 
      }]);
    } catch (e) {
      console.error(e);
      setMessages(prev => [...prev, { role: 'model', text: "Strategic Audit system encountered a technical error." }]);
    } finally {
      setIsLoading(false);
    }
  };

  const handleSend = async () => {
    if (!input.trim() || isLoading) return;

    const userMsg = input.trim();
    setInput('');
    setMessages(prev => [...prev, { role: 'user', text: userMsg }]);
    setIsLoading(true);

    try {
      // Fix: Initialize GoogleGenAI strictly using process.env.API_KEY
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const currentItems = (data || []).slice(-15).map(i => ({ c: i.component, fm: i.failureMode }));

      const prompt = `
        USER REQUEST: "${userMsg}"
        CURRENT STUDY ITEMS: ${JSON.stringify(currentItems)}
        LANGUAGE: ${language}

        MIRA FACILITATOR PROTOCOL:
        1. Be a professional reliability mentor.
        2. If the user asks for suggestions or if the context warrants it, generate new technical RCM items.
        3. EVERY proposed new item or update MUST be wrapped in <ACTION> tags.

        ${RCM_FIELDS_PROMPT}

        Ensure technical strings in JSON are in ${language}.
      `;

      const response = await ai.models.generateContent({
        model: 'gemini-3-pro-preview',
        contents: [{ role: 'user', parts: [{ text: prompt }] }],
        config: {
          thinkingConfig: { thinkingBudget: 32768 },
          temperature: 0.4,
          seed: 42,
          systemInstruction: `You are MIRA, the Lead RCM Facilitator. You synthesize SAE JA1011 strategies in ${language}. You always provide implementable technical additions using <ACTION> tags when helping the user build their study.`
        }
      });

      const { cleanText, proposals } = parseAIResponse(response.text || "");
      setMessages(prev => [...prev, { 
        role: 'model', 
        text: cleanText || "Analysis complete. See technical recommendations below.", 
        proposals 
      }]);
    } catch (error) {
      setMessages(prev => [...prev, { role: 'model', text: "Facilitator session interrupted by a network event." }]);
    } finally {
      setIsLoading(false);
    }
  };

  const applySingleAction = (proposalId: string, messageIndex: number) => {
    setMessages(prevMessages => {
      const message = prevMessages[messageIndex];
      if (!message || !message.proposals) return prevMessages;

      const proposal = message.proposals.find(p => p.id === proposalId);
      if (!proposal || proposal.applied || !proposal.item) return prevMessages;

      let newData = data ? [...data] : [];

      if (proposal.type === 'ADD') {
        const item = proposal.item;

        const getScore = (val: any, def: number) => {
          if (typeof val === 'number') return val;
          if (typeof val === 'string') {
            const match = val.match(/\d+/);
            return match ? parseInt(match[0]) : def;
          }
          return def;
        };

        const s = getScore(item.severity, 5);
        const o = getScore(item.occurrence, 3);
        const d = getScore(item.detection, 4);
        const rpnValue = s * o * d;

        // Fix: Added componentType to fix RCMItem type error
        const newItem: RCMItem = {
          id: `rcm-mir-${Date.now()}-${Math.random().toString(36).substr(2, 5)}`,
          component: item.component || 'Synthesized Component',
          componentType: (item.componentType as any) || 'Mechanical',
          functionType: (item.functionType as any) || 'Primary',
          function: item.function || 'Functional requirement.',
          functionalFailure: item.functionalFailure || 'Loss of function.',
          failureMode: item.failureMode || 'Failure mechanism.',
          failureEffect: item.failureEffect || 'Local/System impact.',
          criticality: (item.criticality as any) || (rpnValue >= 100 ? 'High' : rpnValue >= 40 ? 'Medium' : 'Low'),
          consequenceCategory: (item.consequenceCategory as ConsequenceCategory) || 'Evident - Operational',
          iso14224Code: item.iso14224Code || 'OTH',
          severity: s,
          occurrence: o,
          detection: d,
          rpn: rpnValue,
          maintenanceTask: item.maintenanceTask || 'Inspection/Task.',
          interval: item.interval || 'Monthly',
          taskType: (item.taskType as any) || 'Condition Monitoring',
          isNew: true,
          isMiraGenerated: true,
          isApproved: false
        };
        newData.push(newItem);
      } 
      else if (proposal.type === 'UPDATE') {
        newData = newData.map(item => {
          const isMatch = proposal.item?.id ? item.id === proposal.item.id : (item.component === proposal.item?.component && item.failureMode === proposal.item?.failureMode);
          if (isMatch) {
            const updated = { ...item, ...proposal.item, isNew: false, isMiraGenerated: true };
            updated.severity = Number(updated.severity) || item.severity;
            updated.occurrence = Number(updated.occurrence) || item.occurrence;
            updated.detection = Number(updated.detection) || item.detection;
            updated.rpn = updated.severity * updated.occurrence * updated.detection;
            return updated as RCMItem;
          }
          return item;
        });
      }

      onUpdate(newData);

      return prevMessages.map((m, idx) => {
        if (idx === messageIndex && m.proposals) {
          return {
            ...m,
            proposals: m.proposals.map(p => p.id === proposalId ? { ...p, applied: true } : p)
          };
        }
        return m;
      });
    });
  };

  return (
    <>
      <div className="fixed bottom-6 right-6 z-40 flex flex-col items-end gap-3 transition-all duration-500">
        <button 
          onClick={() => setIsOpen(!isOpen)}
          className={`flex items-center gap-3 p-4 sm:px-6 sm:py-4 rounded-[1.8rem] shadow-2xl transition-all active:scale-95 border ${isOpen ? 'bg-white text-slate-900 border-slate-100' : 'bg-indigo-600 text-white border-indigo-500 hover:bg-indigo-700'}`}
        >
          <div className={`p-2 rounded-xl ${isOpen ? 'bg-indigo-50 text-indigo-600' : 'bg-white/20'}`}>
            <Zap size={22} className={isOpen ? 'fill-indigo-600' : 'fill-white'} />
          </div>
          <span className="hidden sm:inline text-xs font-black uppercase tracking-widest">{isOpen ? 'Close MIRA' : 'Talk to MIRA'}</span>
        </button>
      </div>

      {isOpen && (
