    link.setAttribute('download', `${fileNameBase}_${targetLang}_Decision_Sheet.csv`);

    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);

    setTimeout(() => setIsExtracting(false), 1500);
  };

